function splitList(text: string): string[] {
  const byNumber = text.split(/\d+\.\s+/).map(s => s.trim()).filter(s => s.length > 2);
  if (byNumber.length > 1) return byNumber;
  return text.split(',').map(s => s.trim()).filter(s => s.length > 2);
}

function getVehicleCompat(code: string): string[] {
  const prefix3 = code.substring(0, 3).toUpperCase();
  if (['P0A', 'P0B', 'P0C', 'P0D'].includes(prefix3)) return ['EV', 'HYBRID'];
  return ['ICE', 'HYBRID'];
}

