async function main() {
  console.log('Iniciando seed Fase 2 - Estructura Relacional...');

  // 1. Limpiar tablas en orden correcto (FK constraints)
  await prisma.codeVehicleCompatibility.deleteMany();
  await prisma.oBDCodeTranslation.deleteMany();
  await prisma.oBDSolution.deleteMany();
  await prisma.oBDCause.deleteMany();
  await prisma.oBDSymptom.deleteMany();
  await prisma.oBDCode.deleteMany();
  await prisma.vehicleType.deleteMany();
  await prisma.oBDCategory.deleteMany();
  await prisma.manufacturer.deleteMany();
  console.log('Tablas limpiadas.');

  // 1b. Fabricantes: centinela genérico (SAE) + marcas principales de
  //     LatAm/US/Canadá listas para recibir códigos OEM en la Fase 3.
  console.log('Creando fabricantes...');
  let genericManufacturerId = 0;
  for (const m of MANUFACTURERS) {
    const created = await prisma.manufacturer.create({ data: m });
    if (m.isGeneric) genericManufacturerId = created.id;
  }
  console.log(`  ${MANUFACTURERS.length} fabricantes creados (genérico id=${genericManufacturerId}).`);

  // 2. Crear categorías
  console.log('Creando categorias...');
  const catMap: Record<string, number> = {};
  for (const cat of CATEGORIES) {
    const created = await prisma.oBDCategory.create({ data: cat });
    catMap[cat.code] = created.id;
  }
  console.log(`  ${CATEGORIES.length} categorias creadas.`);

  // 3. Crear tipos de vehículo
  console.log('Creando tipos de vehiculo...');
  const vtMap: Record<string, number> = {};
  for (const vt of VEHICLE_TYPES) {
    const created = await prisma.vehicleType.create({ data: vt });
    vtMap[vt.type] = created.id;
  }
  console.log(`  ${VEHICLE_TYPES.length} tipos de vehiculo creados.`);

  // 4. Combinar códigos curados (incluye EV) + códigos nuevos del CSV
  const existingCodes = new Set(ALL_CODES.map((c) => c.code.toUpperCase()));
  const CSV_PATH = path.resolve(__dirname, '..', '..', 'OBD2_CODES_500.csv');
  const csvCodes = loadCsvCodes(CSV_PATH, existingCodes);
  const MERGED = [...ALL_CODES, ...csvCodes];
  console.log(`  Curados: ${ALL_CODES.length} · Nuevos del CSV: ${csvCodes.length} · Total: ${MERGED.length}`);

  // 5. Crear códigos con relaciones
  console.log(`Insertando ${MERGED.length} codigos OBD2...`);
  let inserted = 0;

  for (const codeData of MERGED) {
    const categoryLetter = codeData.code[0].toUpperCase();
    const categoryId = catMap[categoryLetter];
    if (!categoryId) {
      console.log(`  SKIP: Categoria no encontrada para ${codeData.code}`);
      continue;
    }

    const created = await prisma.oBDCode.create({
      data: {
        code: codeData.code,
        title: codeData.title,
        description: codeData.description,
        severity: codeData.severity,
        categoryId,
        manufacturerId: genericManufacturerId,
        status: 'PUBLISHED',
        source: 'seed',
      },
    });

    for (const symptom of splitList(codeData.symptoms)) {
      await prisma.oBDSymptom.create({ data: { codeId: created.id, symptom } });
    }
    for (const cause of splitList(codeData.causes)) {
      await prisma.oBDCause.create({ data: { codeId: created.id, cause } });
    }
    for (const solution of splitList(codeData.solutions)) {
      await prisma.oBDSolution.create({ data: { codeId: created.id, solution } });
    }
    for (const vType of getVehicleCompat(codeData.code)) {
      const vehicleTypeId = vtMap[vType];
      if (vehicleTypeId) {
        await prisma.codeVehicleCompatibility.create({
          data: { codeId: created.id, vehicleTypeId, applicable: true },
        });
      }
    }

    inserted++;
    if (inserted % 20 === 0 || inserted === MERGED.length) {
      console.log(`  [${inserted}/${MERGED.length}] Insertados...`);
    }
  }

  const total = await prisma.oBDCode.count();
  console.log(`\n${total} codigos insertados.`);

  // 6. Traducciones al inglés (primer lote de códigos de alto tráfico)
  console.log('Cargando traducciones EN...');
  const tr = await loadEnglishTranslations(prisma);
  console.log(`  ${tr.loaded} traducciones EN cargadas${tr.missing.length ? ` (omitidos: ${tr.missing.join(', ')})` : ''}.`);

  // 7. Códigos OEM por fabricante (Fase 3), con su contenido ES + EN
  console.log('Cargando códigos OEM por fabricante...');
  const oem = await loadOemCodes(prisma);
  console.log(`  ${oem.loaded} códigos OEM cargados${oem.skipped.length ? ` (omitidos: ${oem.skipped.join(', ')})` : ''}.`);

  console.log('\nSeed completado.');
}

main()
  .catch((e) => {
    console.error('Error en seed:', e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });
